from concurrent.futures import ThreadPoolExecutor, as_completed
from anthropic.types import ToolUseBlock


def _dispatch_tools(
    tool_blocks: list[ToolUseBlock],
    trace_id: str,
    parent_id: str,
) -> dict[str, object]:
    """Run all tool calls concurrently; each gets its own child span."""
    results: dict[str, object] = {}

    def run_one(block: ToolUseBlock) -> tuple[str, object]:
        span = tracer.start("tool_call", trace_id, parent_id=parent_id)
        try:
            result = TOOL_REGISTRY[block.name](**block.input)
            span.finish(tool=block.name, status="ok")
            return block.id, result
        except Exception as exc:
            span.finish(tool=block.name, status="error", error=str(exc))
            raise

    with ThreadPoolExecutor() as pool:
        futures = {pool.submit(run_one, b): b for b in tool_blocks}
        for fut in as_completed(futures):
            tool_id, result = fut.result()
            results[tool_id] = result

    return results


# Both tool_call spans share trace_id and the same parent_id (llm_call span_id)
# → they appear as sibling spans in the trace tree, overlapping in the timeline

def build_trace_tree(spans: list[Span]) -> dict:
    by_id = {s.span_id: s for s in spans}
    children: dict[str, list[Span]] = {s.span_id: [] for s in spans}
    root = None
    for s in spans:
        if s.parent_id is None:
            root = s
        else:
            children[s.parent_id].append(s)

    def _node(span: Span) -> dict:
        kids = sorted(children[span.span_id], key=lambda c: c.start)
        return {
            "name": span.name,
            "span_id": span.span_id,
            "duration_ms": span.duration_ms,
            "attrs": span.attrs,
            "children": [_node(k) for k in kids],
        }

    return _node(root) if root else {}


def critical_path(spans: list[Span]) -> list[Span]:
    """Spans on the critical path (longest chain by duration)."""
    tree = {s.span_id: s for s in spans}
    children: dict[str, list[Span]] = {s.span_id: [] for s in spans}
    for s in spans:
        if s.parent_id:
            children[s.parent_id].append(s)

    def _longest(span: Span) -> list[Span]:
        kids = children[span.span_id]
        if not kids:
            return [span]
        best = max((_longest(k) for k in kids), key=lambda p: sum(x.duration_ms for x in p))
        return [span] + best

    root = next(s for s in spans if s.parent_id is None)
    return _longest(root)

from dataclasses import dataclass

@dataclass
class Session:
    session_id: str
    turn_traces: list[str]  # trace_ids in order


def run_conversation(session_id: str, turns: list[str], tools: list[dict]) -> list[dict]:
    session = Session(session_id=session_id, turn_traces=[])
    outputs = []
    messages: list[dict] = []

    for user_msg in turns:
        trace_id = uuid.uuid4().hex[:8]
        session.turn_traces.append(trace_id)

        root = tracer.start("agent_turn", trace_id)
        root.attrs["session_id"] = session_id
        root.attrs["turn"] = len(session.turn_traces)

        messages.append({"role": "user", "content": user_msg})
        # ... run agent, extend messages ...
        root.finish(status="ok")
        outputs.append({"trace_id": trace_id, "turn": len(session.turn_traces)})

    return outputs


def fetch_session_traces(session_id: str) -> list[list[Span]]:
    """Group all recorded spans by session_id attribute."""
    by_trace: dict[str, list[Span]] = {}
    for span in tracer._spans:
        if span.attrs.get("session_id") == session_id:
            by_trace.setdefault(span.trace_id, []).append(span)
    return list(by_trace.values())

TRACE_THRESHOLDS = {
    "total_ms": 5000,   # full turn should finish in 5s
    "turns": 6,          # more than 6 model calls is suspicious
    "tool_calls": 10,    # runaway tool dispatch
    "input_tokens": 60_000,  # approaching context limit
}


def check_trace_health(spans: list[Span]) -> list[str]:
    alerts: list[str] = []
    root = next((s for s in spans if s.parent_id is None), None)
    if not root:
        return ["no root span found"]

    if root.duration_ms > TRACE_THRESHOLDS["total_ms"]:
        alerts.append(
            f"slow turn: {root.duration_ms}ms > {TRACE_THRESHOLDS['total_ms']}ms"
        )

    turns = sum(1 for s in spans if s.name == "llm_call")
    if turns > TRACE_THRESHOLDS["turns"]:
        alerts.append(f"excessive turns: {turns}")

    tool_calls = sum(1 for s in spans if s.name == "tool_call")
    if tool_calls > TRACE_THRESHOLDS["tool_calls"]:
        alerts.append(f"too many tool calls: {tool_calls}")

    total_in = sum(s.attrs.get("input_tokens", 0) for s in spans if s.name == "llm_call")
    if total_in > TRACE_THRESHOLDS["input_tokens"]:
        alerts.append(f"high token usage: {total_in} input tokens")

    return alerts
